class Solution(object):
    def findValidPair(self, s):
        from collections import Counter
        cnt = Counter(s)
        for i in range(len(s) - 1):
            a, b = s[i], s[i + 1]
            if a != b and cnt[a] == int(a) and cnt[b] == int(b):
                return a + b
        return ''
